+            "DELETE request to LaunchDarkly API removes projects."
+        ),
+        destructive_pattern!(
+            "launchdarkly-api-delete-generic",
+            r"curl\s+.*(?:-X\s+DELETE|--request\s+DELETE)\s+.*app\.launchdarkly\.com/api/",
